import{_ as t,o,c as i,ai as a}from"./chunks/framework.B3x_xFnx.js";const p=JSON.parse('{"title":"Community Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"ForUsers/CommunityGuidelines.md","filePath":"ForUsers/CommunityGuidelines.md"}'),n={name:"ForUsers/CommunityGuidelines.md"};function s(r,e,l,m,c,u){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="community-guidelines" tabindex="-1">Community Guidelines <a class="header-anchor" href="#community-guidelines" aria-label="Permalink to “Community Guidelines”">​</a></h1><h3 id="this-is-applicable-to-pixelos-chat-and-all-pixelos-affiliated-telegram-communities" tabindex="-1">This is applicable to <a href="https://t.me/pixeloschat" target="_blank" rel="noreferrer">PixelOS Chat</a> and all PixelOS affiliated Telegram Communities. <a class="header-anchor" href="#this-is-applicable-to-pixelos-chat-and-all-pixelos-affiliated-telegram-communities" aria-label="Permalink to “This is applicable to PixelOS Chat and all PixelOS affiliated Telegram Communities.”">​</a></h3><p>The PixelOS Telegram community is a place for users of our custom ROM to ask questions, share feedback, and discuss all things related to PixelOS. All members of the community are expected to follow the rules listed below. Failure to do so may result in a warning or the removal of you from the community.</p><ol><li><p>Do not post or share any illegal or pirated content in the community. This includes links to pirated software, apps, or other content.</p></li><li><p>Do not post or share any explicit or inappropriate content in the community. This includes pornography, violence, or any other content that may be offensive to others.</p></li><li><p>Do not use offensive, hateful, or discriminatory language in the community. This includes racist, sexist, homophobic, or otherwise discriminatory language. However, occasional use of bad language is acceptable, but if it becomes excessive, it will not be tolerated.</p></li><li><p>Do not harass, bully, or abuse other members of the community. This includes personal attacks, insults, or any other behavior that is intended to harm or upset others.</p></li><li><p>Do not ask for ETAs (estimated time of arrival) for updates or releases. The development process can be unpredictable and we cannot provide accurate ETAs for our releases.</p></li><li><p>Do not have long conversations in languages other than English. While we welcome users from all over the world, the main language of our community is English. If you do not know English, please use a translator to communicate in the community.</p></li><li><p>Avoid off-topic discussions in the community. While we encourage healthy discussion and debate, we ask that all topics stay on topic and relevant to PixelOS.</p></li><li><p>Do not spam or promote any products or services in the community without prior approval from the community moderators.</p></li><li><p>Do not use inappropriate profile pictures in the community. This includes explicit or offensive images.</p></li><li><p>Do not misuse the report function in the community. Only use this function to report content or behavior that violates the rules of the community.</p></li><li><p>Do not message anyone privately without their permission. If you have a question or concern, please ask it in the appropriate community.</p></li><li><p>Do not engage in witch-hunting or revealing private information about other members of the community.</p></li><li><p>Respect and follow the decisions of the community moderators and admins. They are here to keep the community running smoothly and to enforce the rules.</p></li><li><p>We encourage users to refer to our website and the XDA forums for instructions and answers to common questions. Please do not repeatedly ask the same questions in the community.</p></li><li><p>We reserve the right to remove any content or accounts that violate these rules or that we deem.</p></li><li><p>We reserve the right to change any of the guidelines specified above at any time without any notice.</p></li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Read the XDA thread for your device before flashing. It has instructions and will be updated should requirements change.</p></div>',5)])])}const d=t(n,[["render",s]]);export{p as __pageData,d as default};
